          source2: "Encyclopaedia Britannica",
          sourceUrl2: "https://www.britannica.com/search?query=2011%20T%C5%8Dhoku%20Tsunami%3A%20Japan%20Greatest%20Modern%20Disaster",
          sourceSnippet2: "Encyclopaedia Britannica — 2011 Tōhoku Tsunami: Japan Greatest Modern Disaster",
          source3: "National Geographic",
          sourceUrl3: "https://www.nationalgeographic.com/search?q=2011%20T%C5%8Dhoku%20Tsunami%3A%20Japan%20Greatest%20Modern%20Disaster",
